from prometheus_client import make_wsgi_app, Counter
from wsgiref.simple_server import make_server
from urllib.parse import urlparse

REQUEST_COUNTER = Counter('http_requests_total', 'Total number of HTTP requests', ['user_id', 'session_id', 'path'])

def track_request(environ):
    user_id = environ.get('USER_ID', 'unknown')
    session_id = environ.get('SESSION_ID', 'unknown')
    full_path = urlparse(environ.get('PATH_INFO', 'unknown')).path
    REQUEST_COUNTER.labels(user_id=user_id, session_id=session_id, path=full_path).inc()

def app(environ, start_response):
    track_request(environ)
    status = '200 OK'
    response_headers = [('Content-type', 'text/plain')]
    start_response(status, response_headers)
    return [b"Hello, World!"]

if __name__ == '__main__':
    app.wsgi_app = make_wsgi_app()
    httpd = make_server('', 8000, app)
    print("Serving on port 8000...")
    httpd.serve_forever()